<style>
	/* Default namespace declaration */@namespace 'http://www.w3.org/1999/xhtml';

	/* Named namespace for SVG */
	@namespace svg 'http://www.w3.org/2000/svg';

	/* Named namespace for MathML */
	@namespace math 'http://www.w3.org/1998/Math/MathML';

	/* Empty namespace */
	@namespace empty '';

	/* Namespace with URL function */
	@namespace xlink url('http://www.w3.org/1999/xlink');

	/* Example usage with namespace prefix */svg|rect{fill:blue;}

*|div{margin:0;}
</style>
